class LUPrefix:

    def __init__(self, n: int):
        self.last_uploaded = 0
        self.uploaded = [False] * (n + 1)

    def upload(self, video: int) -> None:
        self.uploaded[video] = True
        self.last_uploaded = max(self.last_uploaded, video)

    def longest(self) -> int:
        for i in range(self.last_uploaded + 1):
            if not self.uploaded[i]:
                return i - 1
        return self.last_uploaded
```
